1	use pyo3::exceptions::{PyRuntimeError, PyValueError};
2	use pyo3::prelude::*;
3	use pyo3::types::{PyBytes, PyDict};
4	use std::collections::{HashMap, HashSet};
5	use std::sync::{Arc, Mutex, MutexGuard};
6	use tokio::runtime::Handle;
7	use tokio::sync::mpsc::error::TrySendError;
8	use tokio::sync::mpsc::{self, Receiver, Sender};
9	
10	use crate::tokenizers::RustTokenizer;
11	use crate::utils::{json_map_to_pydict, py_value_to_json_string};
12	
13	#[derive(Debug, Clone)]
14	pub enum ResponseChunk {
15	    Data(ResponseData),
16	    Finished(ResponseData),
17	    Error(String),
18	}
19	
20	impl ResponseChunk {
21	    fn is_terminal(&self) -> bool {
22	        matches!(self, Self::Finished(_) | Self::Error(_))
23	    }
24	}
25	
26	#[derive(Debug, Clone)]
27	pub struct ResponseData {
28	    pub text: Option<String>,
29	    pub output_ids: Option<Vec<i32>>,
30	    pub embedding: Option<Vec<f32>>,
31	    pub json_bytes: Option<Vec<u8>>,
32	    pub meta_info: HashMap<String, String>,
33	}
34	
35	pub const DEFAULT_RESPONSE_CHANNEL_CAPACITY: usize = 64;
36	
37	type BridgeStateRef = Arc<Mutex<BridgeState>>;
38	
39	#[derive(Default)]
40	struct BridgeState {
41	    channels: HashMap<String, Sender<ResponseChunk>>,
42	    pending_sends: HashSet<String>,
43	    ready_callbacks: HashMap<String, PyObject>,
44	    ready_signals: HashSet<String>,
45	    terminal_errors: HashMap<String, TerminalError>,
46	}
47	
48	#[derive(Debug, Clone)]
49	pub enum TerminalError {
50	    ChannelFull { rid: String },
51	    ClientDisconnected { rid: String },
52	    Aborted { rid: String },
53	}
54	
55	impl TerminalError {
56	    pub fn message(&self) -> String {
57	        match self {
58	            Self::ChannelFull { rid } => {
59	                format!("gRPC response channel full for {rid}: client not consuming")
60	            }
61	            Self::ClientDisconnected { rid } => {
62	                format!("gRPC client disconnected for request {rid}")
63	            }
64	            Self::Aborted { rid } => format!("Request aborted: {rid}"),
65	        }
66	    }
67	}
68	
69	#[pyclass(eq, eq_int)]
70	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
71	pub enum ChunkSendStatus {
72	    Ready,
73	    Pending,
74	    Closed,
75	}
76	
77	fn lock_or_recover<'a, T>(mutex: &'a Mutex<T>, name: &'static str) -> MutexGuard<'a, T> {
78	    mutex.lock().unwrap_or_else(|poisoned| {
79	        tracing::warn!(mutex = name, "Recovering from poisoned gRPC bridge mutex");
80	        poisoned.into_inner()
81	    })
82	}
83	
84	/// Holds a reference to the Python RuntimeHandle and manages per-request channels.
85	pub struct PyBridge {
86	    runtime_handle: PyObject,
87	    state: BridgeStateRef,
88	    rust_tokenizer: Option<RustTokenizer>,
89	    context_len: i32,
90	    response_channel_capacity: usize,
91	    tokio_handle: Handle,
92	}
93	
94	impl PyBridge {
95	    pub fn new(
96	        runtime_handle: PyObject,
97	        rust_tokenizer: Option<RustTokenizer>,
98	        context_len: i32,
99	        response_channel_capacity: usize,
100	        tokio_handle: Handle,
101	    ) -> Self {
102	        debug_assert!(
103	            response_channel_capacity > 0,
104	            "response_channel_capacity must be normalized by start_server"
105	        );
106	        Self {
107	            runtime_handle,
108	            state: Arc::new(Mutex::new(BridgeState::default())),
109	            rust_tokenizer,
110	            context_len,
111	            response_channel_capacity,
112	            tokio_handle,
113	        }
114	    }
115	
116	    /// Access the Rust tokenizer (if available).
117	    pub fn rust_tokenizer(&self) -> Option<&RustTokenizer> {
118	        self.rust_tokenizer.as_ref()
119	    }
120	
121	    /// Return the model's context length.
122	    pub fn context_len(&self) -> i32 {
123	        self.context_len
124	    }
125	
126	    // ------------------------------------------------------------------
127	    // Channel + callback helpers
128	    // ------------------------------------------------------------------
129	
130	    fn create_channel(&self, rid: &str) -> PyResult<Receiver<ResponseChunk>> {
131	        let (sender, receiver) = mpsc::channel(self.response_channel_capacity);
132	        let mut state = lock_or_recover(self.state.as_ref(), "state");
133	        if state.channels.contains_key(rid) {
134	            return Err(PyRuntimeError::new_err(format!(
135	                "Duplicate active gRPC request id: {}",
136	                rid
137	            )));
138	        }
139	        state.channels.insert(rid.to_string(), sender);
140	        state.terminal_errors.remove(rid);
141	        state.ready_callbacks.remove(rid);
142	        state.ready_signals.remove(rid);
143	        state.pending_sends.remove(rid);
144	        Ok(receiver)
145	    }
146	
147	    fn make_chunk_callback(&self, py: Python<'_>, rid: String) -> PyResult<PyObject> {
148	        let callback = ChunkCallback {
149	            rid,
150	            state: self.state.clone(),
151	            runtime_handle: self.runtime_handle.clone_ref(py),
152	            tokio_handle: self.tokio_handle.clone(),
153	        };
154	        let py_callback = Py::new(py, callback)?;
155	        Ok(py_callback.into_any())
156	    }
157	
158	    fn make_json_callback(&self, py: Python<'_>, rid: String) -> PyResult<PyObject> {
159	        let callback = JsonChunkCallback {
160	            rid,
161	            state: self.state.clone(),
162	            runtime_handle: self.runtime_handle.clone_ref(py),
163	            tokio_handle: self.tokio_handle.clone(),
164	        };
165	        let py_callback = Py::new(py, callback)?;
166	        Ok(py_callback.into_any())
167	    }
168	
169	    // ------------------------------------------------------------------
170	    // Consolidated request submission (generate / embed / classify)
171	    // ------------------------------------------------------------------
172	
173	    /// Submit a generate or embed request by passing a pre-built dict to Python.
174	    ///
175	    /// `req_type` is "generate", "embed", or "classify".
176	    /// `req_dict` contains fields matching GenerateReqInput or EmbeddingReqInput.
177	    pub fn submit_request(
178	        &self,
179	        rid: &str,
180	        req_type: &str,
181	        req_dict: HashMap<String, serde_json::Value>,
182	    ) -> PyResult<Receiver<ResponseChunk>> {
183	        let receiver = self.create_channel(rid)?;
184	        let rid_owned = rid.to_string();
185	
186	        let result = Python::with_gil(|py| -> PyResult<()> {
187	            let py_req_dict = json_map_to_pydict(py, &req_dict)?;
188	            let callback = self.make_chunk_callback(py, rid_owned)?;
189	
190	            let kwargs = PyDict::new(py);
191	            kwargs.set_item("req_type", req_type)?;
192	            kwargs.set_item("req_dict", py_req_dict)?;
193	            kwargs.set_item("chunk_callback", callback)?;
194	
195	            self.runtime_handle
196	                .call_method(py, "submit_request", (), Some(&kwargs))?;
197	            Ok(())
198	        });
199	
200	        match result {
201	            Ok(()) => Ok(receiver),
202	            Err(err) => {
203	                self.remove_channel(rid);
204	                Err(err)
205	            }
206	        }
207	    }
