449	fn close_channel_with_error(
450	    py: Python<'_>,
451	    rid: &str,
452	    state: &BridgeStateRef,
453	    runtime_handle: &PyObject,
454	    error: TerminalError,
455	) {
456	    let mut state = lock_or_recover(state.as_ref(), "state");
457	    remove_channel_refs_locked(&mut state, rid);
458	    state.terminal_errors.insert(rid.to_string(), error);
459	    drop(state);
460	    let _ = runtime_handle.call_method1(py, "abort", (rid, false));
461	}
